import React from 'react';
import SchemeCard from '../components/SchemeCard';

const SchemesPage = () => {
  return (
    <div className="max-w-4xl mx-auto">
      <h1 className="text-3xl font-bold text-gray-900 mb-6">Government Schemes</h1>
      <SchemeCard />
    </div>
  );
};

export default SchemesPage;
